class Solution:
    def canConvertString(self, s: str, t: str, k: int) -> bool:
        if len(s) != len(t):
            return False
        shifts = []
        for a, b in zip(s, t):
            shift = (ord(b) - ord(a)) % 26
            if shift != 0:
                shifts.append(shift)
        shifts.sort()
        for i, shift in enumerate(shifts):
            if shift > i + 1:
                return False
            if (i + 1) + shift > k + 1:
                return False
        return True
